class Solution {
public:
    long long mostPoints(vector<vector<int>>& questions) {
        long long maxPoints = 0;
        int i = 0;
        while (i < questions.size()) {
            long long points = questions[i][0];
            int brainpower = questions[i][1];
            maxPoints += points;
            i += brainpower;
        }
        return maxPoints;
    }
};
```
efficiency: HIGH
time complexity: O(N)
space complexity: O(1)
energy implications: LOW 
explanation: The solution iterates through the questions array once, calculating the maximum points achievable by solving each question and skipping the subsequent brainpower questions. This greedy approach ensures that the highest-scoring questions are selected, maximizing the total points earned.

